1	function fb = csirs_feedback(carrier, csirs, H_est_full, nVar_all, slotAssign)
2	%CSIRS_FEEDBACK  CSI feedback (RI/PMI/CQI/Cap) for Approaches B, C, D.
3	%
4	%  Approach B: Full 128-port SVD upper bound (ideal reference)
5	%  Approach C: Rel-19 Type I Single-Panel Mode A (TS 38.214 S5.2.2.2.1a)
6	%  Approach D: Rel-19 Type I Single-Panel Mode B (TS 38.214 S5.2.2.2.1a)
7	%
8	%  CQI for C/D: computed via nr5g.internal.nrCQISelect (L2SM/MIESM,
9	%  BLER threshold 10%, per TS 38.214 S5.2.2.1) — now supports Rel-19.
10	%
11	%  Inputs:
12	%    carrier      - nrCarrierConfig
13	%    csirs        - {1x4} nrCSIRSConfig objects (csirs{1} used for C/D)
14	%    H_est_full   - [K x 28 x nRx x 128] estimated channel
15	%    nVar_all     - [1x4] noise variance per resource
16	%    slotAssign   - [1x4] slot index per resource
17	%
18	%  Output:
19	%    fb - struct:
20	%           .ri_B,  .cqi_B,  .cap_B,  .W_B
21	%           .ri_C,  .cqi_C,  .cap_C,  .W_C,  .sinrPerRE_C
22	%           .ri_D,  .cqi_D,  .cap_D,  .W_D,  .sinrPerRE_D
23	%         cqi_* is wideband scalar; cap_* is scalar (bits/s/Hz)
24	
25	nRxAntennas  = size(H_est_full, 3);
26	nTxAntennas  = size(H_est_full, 4);
27	nPortsPerRes = nTxAntennas / 4;
28	nSymPerSlot  = carrier.SymbolsPerSlot;
29	
30	% ── Wideband channel matrix H_wb [nRx x nTx] ─────────────────────────────
31	H_wb = zeros(nRxAntennas, nTxAntennas);
32	for r = 1:4
33	    pS = (r-1)*nPortsPerRes + 1;  pE = r*nPortsPerRes;
34	    sS = slotAssign(r)*nSymPerSlot + 1;
35	    sE = (slotAssign(r)+1)*nSymPerSlot;
36	    H_wb(:, pS:pE) = squeeze(mean(H_est_full(:, sS:sE, :, pS:pE), [1 2]));
37	end
38	
39	nVar_wb = mean(nVar_all);
40	
41	% Broadcast H_wb to [K x L x nRx x nTx] for nrPMIReport / nrCQISelect
42	carrier.NSlot = 0;
43	nSC = carrier.NSizeGrid * 12;
44	H_4d = repmat(reshape(H_wb, 1, 1, nRxAntennas, nTxAntennas), ...
45	              [nSC, carrier.SymbolsPerSlot, 1, 1]);
46	
47	% ── Subband size per TS 38.214 Table 5.2.1.4-2 (smallest valid value) ────
48	nSizeBWP = carrier.NSizeGrid;
49	if nSizeBWP >= 145
50	    subbandSize = 16;
51	elseif nSizeBWP >= 73
52	    subbandSize = 8;
53	elseif nSizeBWP >= 24
54	    subbandSize = 4;
55	else
56	    subbandSize = [];   % BWP < 24 PRBs: no subbands
57	end
58	
59	% ── Shared struct for nrCQISelect (Rel-19, now supported) ────────────────
60	cqiCfg.NSizeBWP        = carrier.NSizeGrid;
61	cqiCfg.NStartBWP       = 0;
62	cqiCfg.CodebookType    = 'typeI-SinglePanel-r19';
63	cqiCfg.PanelDimensions = [1, 16, 4];
64	cqiCfg.PMIMode         = 'Subband';
65	cqiCfg.SubbandSize     = subbandSize;
66	cqiCfg.CQIMode         = 'Wideband';
67	cqiCfg.CQITable        = 'table1';
68	
69	% =========================================================================
70	%  APPROACH B: Full 128-Port SVD Upper Bound
71	%  CQI: ZF SINR per layer → threshold table (wideband SVD, no codebook grid)
72	% =========================================================================
73	[~, S_B, V_B]    = svd(H_wb, 'econ');
74	singVals_B       = diag(S_B);
75	snr_sv_B         = singVals_B.^2 / nVar_wb;
76	riThresh_B       = 0.1 * singVals_B(1);
77	ri_B             = min(sum(singVals_B > riThresh_B), nRxAntennas);
78	W_B              = V_B(:, 1:ri_B);
79	
80	H_eff_B = H_wb * W_B;
81	W_zf_B  = pinv(H_eff_B);
82	sinr_B  = zeros(ri_B, 1);
83	for lyr = 1:ri_B
84	    sig  = abs(W_zf_B(lyr,:) * H_eff_B(:,lyr))^2;
85	    intf = sum(abs(W_zf_B(lyr,:) * H_eff_B).^2) - sig;
86	    nse  = nVar_wb * norm(W_zf_B(lyr,:))^2;
87	    sinr_B(lyr) = sig / (intf + nse);
88	end
89	cqi_tbl = [-6.7,-4.7,-2.3,0.2,2.4,4.7,6.9,9.3,10.7,12.2,14.1,15.6,18.0,20.3,22.7];
90	sinr_B_dB = 10*log10(sinr_B);
91	cqi_B     = max(sum(mean(sinr_B_dB) >= cqi_tbl), 1);   % wideband scalar
92	cap_B     = sum(log2(1 + snr_sv_B(1:ri_B) / ri_B));
93	
94	fb.ri_B   = ri_B;
95	fb.cqi_B  = cqi_B;
96	fb.cap_B  = cap_B;
97	fb.W_B    = W_B;
98	fb.sinr_B = sinr_B;   % [ri_B x 1] per-layer wideband ZF SINR (linear)
99	
100	% =========================================================================
101	%  APPROACH C: Rel-19 Mode A
102	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
103	%  CQI: nrCQISelect (L2SM/MIESM) — now supports typeI-SinglePanel-r19
104	% =========================================================================
105	riCfg_C.NSizeBWP        = carrier.NSizeGrid;
106	riCfg_C.NStartBWP       = 0;
107	riCfg_C.CodebookType    = 'typeI-SinglePanel-r19';
108	riCfg_C.PanelDimensions = [1, 16, 4];
109	riCfg_C.CodebookMode    = 1;
110	riCfg_C.PMIMode         = 'Subband';
111	riCfg_C.SubbandSize     = subbandSize;
112	[ri_C, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_C, H_4d, nVar_wb);
113	
114	cqiCfg_C             = cqiCfg;
115	cqiCfg_C.CodebookMode = 1;
116	[cqi_C_vec, ~, ~, pmiInfo_C] = nr5g.internal.nrCQISelect( ...
117	    carrier, csirs{1}, cqiCfg_C, ri_C, H_4d, nVar_wb);
118	cqi_C = cqi_C_vec(1);   % wideband CQI (row 1 = wideband)
119	W_C   = pmiInfo_C.W(:,:,1);   % first subband precoder for wideband capacity approx
120	cap_C = real(log2(det(eye(nRxAntennas) + ...
121	    (1/nVar_wb) * (H_wb*W_C*(H_wb*W_C)'))));
122	
123	fb.ri_C        = ri_C;
124	fb.cqi_C       = cqi_C;
125	fb.cap_C       = cap_C;
126	fb.W_C         = W_C;
127	fb.sinrPerRE_C = pmiInfo_C.SINRPerREPMI;
128	
129	% =========================================================================
130	%  APPROACH D: Rel-19 Mode B
131	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
132	%  CQI: nrCQISelect (L2SM/MIESM) — typeI-SinglePanel-r19
133	% =========================================================================
134	riCfg_D.NSizeBWP        = carrier.NSizeGrid;
135	riCfg_D.NStartBWP       = 0;
136	riCfg_D.CodebookType    = 'typeI-SinglePanel-r19';
137	riCfg_D.PanelDimensions = [1, 16, 4];
138	riCfg_D.CodebookMode    = 2;
139	riCfg_D.PMIMode         = 'Subband';
140	riCfg_D.SubbandSize     = subbandSize;
141	[ri_D, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_D, H_4d, nVar_wb);
142	
143	cqiCfg_D             = cqiCfg;
144	cqiCfg_D.CodebookMode = 2;
145	cqiCfg_D.PMIMode      = 'Wideband';   % Mode B uses nrPMIReport (wideband-only)
146	[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
147	    carrier, csirs{1}, cqiCfg_D, ri_D, H_4d, nVar_wb);
148	cqi_D = cqi_D_vec(1);
149	W_D   = pmiInfo_D.W(:,:,1);   % first subband precoder for wideband capacity approx
150	cap_D = real(log2(det(eye(nRxAntennas) + ...
151	    (1/nVar_wb) * (H_wb*W_D*(H_wb*W_D)'))));
152	
153	fb.ri_D        = ri_D;
154	fb.cqi_D       = cqi_D;
155	fb.cap_D       = cap_D;
156	fb.W_D         = W_D;
157	fb.sinrPerRE_D = pmiInfo_D.SINRPerREPMI;
158	
159	end
