103	    intf = sum(abs(W_zf_B(lyr,:) * H_eff_B).^2) - sig;
104	    nse  = nVar_wb * norm(W_zf_B(lyr,:))^2;
105	    sinr_B(lyr) = sig / (intf + nse);
106	end
107	cqi_tbl = [-6.7,-4.7,-2.3,0.2,2.4,4.7,6.9,9.3,10.7,12.2,14.1,15.6,18.0,20.3,22.7];
108	sinr_B_dB = 10*log10(sinr_B);
109	cqi_B     = max(sum(mean(sinr_B_dB) >= cqi_tbl), 1);   % wideband scalar
110	cap_B     = sum(log2(1 + snr_sv_B(1:ri_B) / ri_B));
111	
112	fb.ri_B   = ri_B;
113	fb.cqi_B  = cqi_B;
114	fb.cap_B  = cap_B;
115	fb.W_B    = W_B;
116	fb.sinr_B = sinr_B;   % [ri_B x 1] per-layer wideband ZF SINR (linear)
117	
118	% =========================================================================
119	%  APPROACH C: Rel-19 Mode A
120	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
121	%  CQI: nrCQISelect (L2SM/MIESM) — now supports typeI-SinglePanel-r19
122	% =========================================================================
123	riCfg_C.NSizeBWP        = carrier.NSizeGrid;
124	riCfg_C.NStartBWP       = 0;
125	riCfg_C.CodebookType    = 'typeI-SinglePanel-r19';
126	riCfg_C.PanelDimensions = [1, 16, 4];
127	riCfg_C.CodebookMode    = 1;
128	riCfg_C.PMIMode         = pmiMode;
129	riCfg_C.SubbandSize     = subbandSize;
130	[ri_C, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_C, H_4d, nVar_wb);
131	
132	cqiCfg_C             = cqiCfg;
133	cqiCfg_C.CodebookMode = 1;
134	[cqi_C_vec, ~, ~, pmiInfo_C] = nr5g.internal.nrCQISelect( ...
135	    carrier, csirs{1}, cqiCfg_C, ri_C, H_4d, nVar_wb);
136	% cqi_C_vec: row 1 = wideband, rows 2..end = per-subband (when CQIMode='Subband')
137	if strcmpi(cqiMode, 'Subband')
138	    cqi_C = cqi_C_vec;   % full vector [1+numSB x 1]
139	else
140	    cqi_C = cqi_C_vec(1);
141	end
142	W_C   = pmiInfo_C.W(:,:,1);   % first subband precoder for wideband capacity approx
143	cap_C = real(log2(det(eye(nRxAntennas) + ...
144	    (1/nVar_wb) * (H_wb*W_C*(H_wb*W_C)'))));
145	
146	fb.ri_C        = ri_C;
147	fb.cqi_C       = cqi_C;
148	fb.cap_C       = cap_C;
149	fb.W_C         = W_C;
150	fb.sinrPerRE_C = pmiInfo_C.SINRPerREPMI;
151	
152	% =========================================================================
153	%  APPROACH D: Rel-19 Mode B
154	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
155	%  CQI: nrCQISelect (L2SM/MIESM) — typeI-SinglePanel-r19
156	% =========================================================================
