168	% Mode B beam group (i1) is always wideband (spec constraint).
169	% Co-phase (i2) follows pmiMode: 'Subband' activates Phase 2 per-subband
170	% co-phase in nrPMIReport, giving consistent W between RI and CQI steps.
171	cqiCfg_D.PMIMode      = pmiMode;
172	[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
173	    carrier, csirs{1}, cqiCfg_D, ri_D, H_4d, nVar_wb);
